/* CSS will be added here */
:root{

  --primary-color:#0d6efd;
  --secondary-color:#ff6b00;

  --success-color:#16a34a;
  --danger-color:#dc2626;
  --warning-color:#f59e0b;

  --white:#ffffff;
  --black:#000000;

  --text-color:#333333;
  --text-light:#666666;

  --bg-color:#f5f5f5;
  --card-bg:#ffffff;

  --border-color:#dddddd;

  --header-height:70px;

  --container-width:1280px;

  --transition:0.3s ease;

  --radius:8px;

  --shadow:0 5px 15px rgba(0,0,0,.08);

}/* ===========================
   CSS RESET
=========================== */

*{
    margin:0;
    padding:0;
    box-sizing:border-box;
}

html{
    scroll-behavior:smooth;
}

body{
    font-family:Arial, Helvetica, sans-serif;
    font-size:16px;
    color:var(--text-color);
    background:var(--bg-color);
    line-height:1.6;
}

a{
    color:inherit;
    text-decoration:none;
}

img{
    max-width:100%;
    display:block;
}

ul,
ol{
    list-style:none;
}

button,
input,
textarea{
    font:inherit;
    outline:none;
    border:none;
}

.container{
    width:100%;
    max-width:var(--container-width);
    margin:auto;
    padding:0 15px;
}/* ======================================
   TYPOGRAPHY
====================================== */

h1,h2,h3,h4,h5,h6{
    color:var(--black);
    font-weight:700;
    line-height:1.3;
    margin-bottom:15px;
}

h1{
    font-size:38px;
}

h2{
    font-size:30px;
}

h3{
    font-size:24px;
}

h4{
    font-size:20px;
}

h5{
    font-size:18px;
}

h6{
    font-size:16px;
}

p{
    margin-bottom:15px;
    color:var(--text-light);
}

small{
    font-size:13px;
}

strong{
    font-weight:700;
}

/* ======================================
   Utility Classes
====================================== */

.text-center{
    text-align:center;
}

.text-left{
    text-align:left;
}

.text-right{
    text-align:right;
}

.d-flex{
    display:flex;
}

.align-center{
    align-items:center;
}

.justify-between{
    justify-content:space-between;
}

.justify-center{
    justify-content:center;
}

.w-100{
    width:100%;
}

.shadow{
    box-shadow:var(--shadow);
}

.radius{
    border-radius:var(--radius);
}

.bg-white{
    background:var(--white);
}

.mt-20{
    margin-top:20px;
}

.mb-20{
    margin-bottom:20px;
}

.pt-20{
    padding-top:20px;
}

.pb-20{
    padding-bottom:20px;
}
